-- إعادة 6 كريدت خُصمت في الاختبار (1 + 5)
UPDATE credit_wallets SET balance = balance + 6, total_earned = total_earned + 6 WHERE user_id = 1;
-- حذف سجلات الاختبار
DELETE FROM credit_transactions WHERE user_id = 1 AND description IN ('اختبار', 'اختبار خصم') ORDER BY created_at DESC LIMIT 2;
SELECT balance FROM credit_wallets WHERE user_id = 1;

